import WebGLVectorTileLayerRenderer from"../renderer/webgl/VectorTileLayer.js";import BaseTileLayer from"./BaseTile.js";class WebGLVectorTileLayer extends BaseTileLayer{constructor(e){super(Object.assign({},e)),this.styleVariables_=e.variables||{},this.style_=e.style,this.hitDetectionDisabled_=!!e.disableHitDetection}createRenderer(){return new WebGLVectorTileLayerRenderer(this,{style:this.style_,variables:this.styleVariables_,disableHitDetection:this.hitDetectionDisabled_,cacheSize:this.getCacheSize()})}updateStyleVariables(e){Object.assign(this.styleVariables_,e),this.changed()}setStyle(e){this.style_=e,this.clearRenderer(),this.changed()}}export default WebGLVectorTileLayer;